397→    private static void prependDefaults(
398→            Map<String, ReaderTag> defaultTags,
399→            ReaderTagList orderedTagList,
400→            Map<String, TagInfo> defaultTagInfo
401→    ) {
402→        if (defaultTags.isEmpty()) return;
403→
404→        List<String> reverseOrderedKeys = new ArrayList<>(defaultTagInfo.keySet());
405→        Collections.reverse(reverseOrderedKeys);
406→
407→        for (String key : reverseOrderedKeys) {
408→            if (defaultTags.containsKey(key)) {
409→                ReaderTag tag = defaultTags.get(key);
410→
411→                orderedTagList.add(0, tag);
412→            }
413→        }
414→    }
415→
416→    private static boolean defaultTagFoundAndAdded(
417→            Map<String, TagInfo> defaultTagInfos,
418→            ReaderTag tag,
419→            Map<String, ReaderTag> defaultTags
420→    ) {
421→        boolean foundAndAdded = false;
422→
423→        for (String key : defaultTagInfos.keySet()) {
424→            if (defaultTagInfos.get(key).isDesiredTag(tag)) {
425→                if (putIfAbsentDone(defaultTags, key, tag)) {
426→                    foundAndAdded = true;
427→                }
428→                break;
429→            }
430→        }
431→
432→        return foundAndAdded;
433→    }
434→
435→    public static ReaderTagList getOrderedTagsList(ReaderTagList tagList, Map<String, TagInfo> defaultTagInfos) {
436→        ReaderTagList orderedTagList = new ReaderTagList();
437→        Map<String, ReaderTag> defaultTags = new HashMap<>();
438→
439→        for (ReaderTag tag : tagList) {
440→            if (defaultTagFoundAndAdded(defaultTagInfos, tag, defaultTags)) continue;
441→
442→            orderedTagList.add(tag);
443→        }
444→        prependDefaults(defaultTags, orderedTagList, defaultTagInfos);
445→
446→        return orderedTagList;
447→    }
