 31→public class ReaderPostLogic {
 32→    private ServiceCompletionListener mCompletionListener;
 33→    private Object mListenerCompanion;
 34→
 35→    public ReaderPostLogic(ServiceCompletionListener listener) {
 36→        mCompletionListener = listener;
 37→    }
 38→
 39→    public void performTask(Object companion, UpdateAction action,
 40→                            ReaderTag tag, long blogId, long feedId) {
 41→        mListenerCompanion = companion;
 42→
 43→        EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action, tag));
 44→
 45→        if (tag != null) {
 46→            updatePostsWithTag(tag, action);
 47→        } else if (blogId > -1) {
 48→            updatePostsInBlog(blogId, action);
 49→        } else if (feedId > -1) {
 50→            updatePostsInFeed(feedId, action);
 51→        }
 52→    }
 53→
 54→
 55→    private void updatePostsWithTag(final ReaderTag tag, final UpdateAction action) {
 56→        requestPostsWithTag(
 57→                tag,
 58→                action,
 59→                new ReaderActions.UpdateResultListener() {
 60→                    @Override
 61→                    public void onUpdateResult(ReaderActions.UpdateResult result) {
 62→                        EventBus.getDefault().post(new ReaderEvents.UpdatePostsEnded(tag, result, action));
 63→                        mCompletionListener.onCompleted(mListenerCompanion);
 64→                    }
 65→                });
 66→    }
 67→
 68→    private void updatePostsInBlog(long blogId, final UpdateAction action) {
 69→        ReaderActions.UpdateResultListener listener = new ReaderActions.UpdateResultListener() {
 70→            @Override
 71→            public void onUpdateResult(ReaderActions.UpdateResult result) {
 72→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsEnded(result, action));
 73→                mCompletionListener.onCompleted(mListenerCompanion);
 74→            }
 75→        };
 76→        requestPostsForBlog(blogId, action, listener);
 77→    }
 78→
 79→    private void updatePostsInFeed(long feedId, final UpdateAction action) {
 80→        ReaderActions.UpdateResultListener listener = new ReaderActions.UpdateResultListener() {
 81→            @Override
 82→            public void onUpdateResult(ReaderActions.UpdateResult result) {
 83→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsEnded(result, action));
 84→                mCompletionListener.onCompleted(mListenerCompanion);
 85→            }
 86→        };
 87→        requestPostsForFeed(feedId, action, listener);
 88→    }
