import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.ui.reader.utils.ReaderUtils
import org.wordpress.android.ui.reader.utils.ReaderUtilsWrapper
import javax.inject.Inject

class BloggingPromptsPostTagProvider @Inject constructor(
    private val readerUtilsWrapper: ReaderUtilsWrapper,
) {
    fun promptIdTag(
        tagUrl: String
    ): String = readerUtilsWrapper.getTagFromTagUrl(tagUrl)
        .takeIf { it.isNotBlank() }
        ?: BLOGGING_PROMPT_TAG

    fun promptIdSearchReaderTag(
        tagUrl: String
    ): ReaderTag {
        val tagName = promptIdTag(tagUrl)
        val tag = readerUtilsWrapper.getTagFromTagName(tagName, ReaderTagType.FOLLOWED)
        // If the tag was found in the database with a proper endpoint, use it as-is.
        // Otherwise, we need to set the proper endpoint so that isTagTopic() returns true.
        // This ensures posts are sorted by date_tagged for proper pagination.
        return if (hasTagEndpoint(tag)) {
            tag
        } else {
            val tagSlug = ReaderUtils.sanitizeWithDashes(tagName)
            val endpoint = String.format(TAG_ENDPOINT_FORMAT, tagSlug)
            ReaderTag(
                tagSlug,
                tagSlug,
                tagName,
                endpoint,
                ReaderTagType.FOLLOWED
            )
        }
    }

    /**
     * Checks if the tag has a proper endpoint set for tag topics.
     * Tags from the database will have the endpoint, while in-memory created tags won't.
     */
    private fun hasTagEndpoint(tag: ReaderTag): Boolean {
        val endpoint = tag.endpoint
        return endpoint.isNotEmpty() && endpoint.contains(TAG_ENDPOINT_PATH)
    }

    companion object {
        const val BLOGGING_PROMPT_TAG = "dailyprompt"
        const val BLOGANUARY_TAG = "bloganuary"
        private const val TAG_ENDPOINT_FORMAT = "read/tags/%s/posts"
        private const val TAG_ENDPOINT_PATH = "/read/tags/"
    }
}"}

